import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionSecure {

    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter a directory name: ");
        String directory = reader.readLine();

        if (!isValidDirectoryInput(directory)) {
            System.out.println("Invalid directory name.");
            return;
        }

        String[] command = {"ls", directory}; // Use an array to pass command and arguments separately

        Process process = Runtime.getRuntime().exec(command);

        BufferedReader resultReader = new BufferedReader(new InputStreamReader(process.getInputStream()));

        String line;
        while ((line = resultReader.readLine()) != null) {
            System.out.println(line);
        }
    }

    private static boolean isValidDirectoryInput(String input) {
        // Implement your validation logic here, e.g., check for allowed characters
        return input.matches("[a-zA-Z0-9_/]+");
    }
}

